// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>Prerequisites</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Confirm every tool is installed before writing a single line of code. Catching version mismatches now saves hours of cryptic errors later.</div>\n<div class=\"step-body\">\n<p>You need <strong>Python 3.10 or newer</strong>. Check your installed versions:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python3 --version <span># must be 3.10+</span>\npip3 --version</pre>\n</div>\n<div>On Windows use <code>python</code> and <code>pip</code> (no 3 suffix). On macOS/Linux use <code>python3</code> / <code>pip3</code> to avoid the system Python 2.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Install <strong>pyenv</strong> to switch Python versions per-project without touching the system Python. Highly recommended on macOS and Linux.</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Create a virtual environment</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A virtual environment isolates this project's packages from everything else. Without one, pip installs globally and version conflicts are inevitable \u2014 especially between projects.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">your project root</span>\n</div>\n<pre>mkdir mysite &amp;&amp; cd mysite\npython3 -m venv venv\nsource venv/bin/activate <span># macOS / Linux</span>\n# venv\\Scripts\\activate <span># Windows PowerShell</span></pre>\n</div>\n<div>Your terminal prompt changes to <code>(venv)</code>. Every <code>pip install</code> from now on lands in <code>venv/</code>, not the system. Run <code>deactivate</code> to exit.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Install Django &amp; lock dependencies</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Pinning versions in <code>requirements.txt</code> guarantees reproducible installs on every developer machine and on the production server.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install django python-dotenv whitenoise gunicorn\npip freeze &gt; requirements.txt\npython -m django --version <span># should print 5.x</span></pre>\n</div>\n<div>\n<strong>What each package does:</strong><br/>\n<code>django</code> \u2014 the framework<br/>\n<code>python-dotenv</code> \u2014 loads <code>.env</code> secrets without hardcoding them<br/>\n<code>whitenoise</code> \u2014 serves static files efficiently from Gunicorn (no Nginx needed on platforms like Railway/Heroku)<br/>\n<code>gunicorn</code> \u2014 production WSGI server\n </div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>Create the project and app</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django splits <em>project</em> (global config) from <em>apps</em> (feature modules). The project never holds business logic \u2014 it just wires apps together. This lets you reuse an app in a future project.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">inside mysite/</span>\n</div>\n<pre>django-admin startproject core . <span># dot = keep manage.py in current dir</span>\npython manage.py startapp pages <span># our Home, About, Contact app</span></pre>\n</div>\n<div>The trailing dot after <code>startproject core</code> prevents Django from creating a redundant outer <code>mysite/</code> wrapper folder. Your <code>manage.py</code> lives directly beside <code>core/</code>.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge\">05</div>\n<h2>Understand the project structure</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Knowing what every file does prevents edits in the wrong place and makes error messages immediately meaningful.</div>\n<div class=\"tree\"><pre><span>mysite/</span>\n\u251c\u2500\u2500 <span>core/</span> <span># project package \u2014 config lives here</span>\n\u2502 \u251c\u2500\u2500 <span>__init__.py</span>\n\u2502 \u251c\u2500\u2500 <span>settings.py</span> <span># all Django settings</span>\n\u2502 \u251c\u2500\u2500 <span>urls.py</span> <span># root URL dispatcher</span>\n\u2502 \u251c\u2500\u2500 <span>asgi.py</span>\n\u2502 \u2514\u2500\u2500 <span>wsgi.py</span> <span># entry point for Gunicorn</span>\n\u251c\u2500\u2500 <span>pages/</span> <span># our feature app</span>\n\u2502 \u251c\u2500\u2500 <span>views.py</span> <span># render each page</span>\n\u2502 \u251c\u2500\u2500 <span>urls.py</span> <span># \u2190 create this yourself</span>\n\u2502 \u251c\u2500\u2500 <span>apps.py</span>\n\u2502 \u2514\u2500\u2500 <span>models.py</span> <span># empty for now</span>\n\u251c\u2500\u2500 <span>templates/</span> <span># \u2190 create this yourself (project-level)</span>\n\u2502 \u251c\u2500\u2500 <span>base.html</span> <span># shared skeleton + navbar</span>\n\u2502 \u251c\u2500\u2500 <span>home.html</span>\n\u2502 \u251c\u2500\u2500 <span>about.html</span>\n\u2502 \u2514\u2500\u2500 <span>contact.html</span>\n\u251c\u2500\u2500 <span>static/</span> <span># \u2190 create this yourself</span>\n\u2502 \u251c\u2500\u2500 <span>css/main.css</span> <span># all styles including navbar</span>\n\u2502 \u2514\u2500\u2500 <span>js/nav.js</span> <span># active-link highlight</span>\n\u251c\u2500\u2500 <span>.env</span> <span># secrets \u2014 never commit</span>\n\u251c\u2500\u2500 <span>.gitignore</span>\n\u251c\u2500\u2500 <span>manage.py</span>\n\u2514\u2500\u2500 <span>requirements.txt</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> We place templates at the <em>project</em> level (not inside the app) because all three pages share a single <code>base.html</code>. A project-level templates folder makes the inheritance obvious at a glance.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge\">06</div>\n<h2>Register the app &amp; configure templates</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django only discovers your app's views and templates once it appears in <code>INSTALLED_APPS</code>. The <code>DIRS</code> path tells Django where the project-level templates folder is.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre><span>from</span> pathlib <span>import</span> Path\n<span>import</span> os\n<span>from</span> dotenv <span>import</span> load_dotenv\n\nload_dotenv() <span># reads .env into os.environ</span>\n\nBASE_DIR = Path(__file__).resolve().parent.parent\n\nSECRET_KEY = os.environ.get(<span>\"SECRET_KEY\"</span>, <span>\"change-me-in-env\"</span>)\nDEBUG = os.environ.get(<span>\"DEBUG\"</span>, <span>\"True\"</span>) == <span>\"True\"</span>\nALLOWED_HOSTS = os.environ.get(<span>\"ALLOWED_HOSTS\"</span>, <span>\"127.0.0.1 localhost\"</span>).split()\n\nINSTALLED_APPS = [\n <span>\"django.contrib.admin\"</span>,\n <span>\"django.contrib.auth\"</span>,\n <span>\"django.contrib.contenttypes\"</span>,\n <span>\"django.contrib.sessions\"</span>,\n <span>\"django.contrib.messages\"</span>,\n <span>\"django.contrib.staticfiles\"</span>,\n <span>\"pages\"</span>, <span># \u2190 add this</span>\n]\n\nTEMPLATES = [\n {\n <span>\"BACKEND\"</span>: <span>\"django.template.backends.django.DjangoTemplates\"</span>,\n <span>\"DIRS\"</span>: [BASE_DIR / <span>\"templates\"</span>], <span># \u2190 project-level templates</span>\n <span>\"APP_DIRS\"</span>: <span>True</span>,\n <span>\"OPTIONS\"</span>: {\n <span>\"context_processors\"</span>: [\n <span>\"django.template.context_processors.debug\"</span>,\n <span>\"django.template.context_processors.request\"</span>,\n <span>\"django.contrib.auth.context_processors.auth\"</span>,\n <span>\"django.contrib.messages.context_processors.messages\"</span>,\n ],\n },\n },\n]\n\nSTATIC_URL = <span>\"/static/\"</span>\nSTATICFILES_DIRS = [BASE_DIR / <span>\"static\"</span>] <span># dev: where Django looks</span>\nSTATIC_ROOT = BASE_DIR / <span>\"staticfiles\"</span> <span># prod: collectstatic output</span>\n\nMIDDLEWARE = [\n <span>\"django.middleware.security.SecurityMiddleware\"</span>,\n <span>\"whitenoise.middleware.WhiteNoiseMiddleware\"</span>, <span># \u2190 serve static in prod</span>\n <span>\"django.contrib.sessions.middleware.SessionMiddleware\"</span>,\n <span>\"django.middleware.common.CommonMiddleware\"</span>,\n <span>\"django.middleware.csrf.CsrfViewMiddleware\"</span>,\n <span>\"django.contrib.auth.middleware.AuthenticationMiddleware\"</span>,\n <span>\"django.contrib.messages.middleware.MessageMiddleware\"</span>,\n <span>\"django.middleware.clickjacking.XFrameOptionsMiddleware\"</span>,\n]</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> WhiteNoise must come <em>immediately after</em> SecurityMiddleware in the list. Any earlier and it can't serve files over HTTPS correctly.</div>\n<div class=\"step-body\"><p>Create your <code>.env</code> file now and add it to <code>.gitignore</code>:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env</span>\n</div>\n<pre>SECRET_KEY=replace-this-with-a-long-random-string\nDEBUG=True\nALLOWED_HOSTS=127.0.0.1 localhost</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.gitignore</span>\n</div>\n<pre>venv/\n.env\n__pycache__/\n*.pyc\nstaticfiles/\ndb.sqlite3</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge\">07</div>\n<h2>Create the template &amp; static directories</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django expects these folders to exist before the dev server starts. Creating them now prevents <code>TemplateDoesNotExist</code> errors on first run.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">inside mysite/</span>\n</div>\n<pre>mkdir -p templates\nmkdir -p static/css static/js</pre>\n</div>\n<div>On Windows use <code>mkdir templates</code>, <code>mkdir static\\css</code>, <code>mkdir static\\js</code> (backslashes, no <code>-p</code>).</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge\">08</div>\n<h2>base.html \u2014 the shared skeleton</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong><code>base.html</code> is the single source of truth for every page's <code>&lt;head&gt;</code>, navbar, and footer. All other templates <em>extend</em> it and only override the blocks they need \u2014 eliminating copy-paste duplication.</div>\n<div class=\"step-body\">\n<p>Create <code>templates/base.html</code> with the full content below. Every line is explained in the annotation table that follows.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/base.html</span>\n</div>\n<pre><span>&lt;!-- 1. Load the {% static %} tag so we can reference CSS/JS --&gt;</span>\n<span>{% load static %}</span>\n<span>&lt;!DOCTYPE html&gt;</span>\n<span>&lt;html</span> <span>lang</span>=<span>\"en\"</span><span>&gt;</span>\n<span>&lt;head&gt;</span>\n <span>&lt;meta</span> <span>charset</span>=<span>\"UTF-8\"</span><span>/&gt;</span>\n <span>&lt;meta</span> <span>name</span>=<span>\"viewport\"</span> <span>content</span>=<span>\"width=device-width, initial-scale=1.0\"</span><span>/&gt;</span>\n\n <span>&lt;!-- 2. {% block title %} \u2014 each page overrides this --&gt;</span>\n <span>&lt;title&gt;</span><span>{% block title %}</span>My Site<span>{% endblock %}</span><span>&lt;/title&gt;</span>\n\n <span>&lt;!-- 3. {% static %} builds the correct URL in dev AND prod --&gt;</span>\n <span>&lt;link</span> <span>rel</span>=<span>\"stylesheet\"</span> <span>href</span>=<span>\"{% static 'css/main.css' %}\"</span><span>/&gt;</span>\n\n <span>&lt;!-- 4. Extra head content a child page may inject (e.g. extra CSS) --&gt;</span>\n <span>{% block extra_head %}{% endblock %}</span>\n<span>&lt;/head&gt;</span>\n<span>&lt;body&gt;</span>\n\n <span>&lt;!-- 5. Navbar \u2014 shared across all pages --&gt;</span>\n <span>&lt;header</span> <span>class</span>=<span>\"site-header\"</span><span>&gt;</span>\n <span>&lt;nav</span> <span>class</span>=<span>\"navbar\"</span> <span>aria-label</span>=<span>\"Main navigation\"</span><span>&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'home' %}\"</span> <span>class</span>=<span>\"nav-brand\"</span><span>&gt;</span>MyBrand<span>&lt;/a&gt;</span>\n\n <span>&lt;!-- 6. Hamburger toggle for mobile --&gt;</span>\n <span>&lt;button</span> <span>class</span>=<span>\"nav-toggle\"</span> <span>aria-expanded</span>=<span>\"false\"</span>\n <span>aria-controls</span>=<span>\"nav-links\"</span> <span>aria-label</span>=<span>\"Toggle menu\"</span><span>&gt;</span>\n <span>&lt;span&gt;&lt;/span&gt;&lt;span&gt;&lt;/span&gt;&lt;span&gt;&lt;/span&gt;</span>\n <span>&lt;/button&gt;</span>\n\n <span>&lt;!-- 7. Nav links \u2014 active class set by nav.js comparing URLs --&gt;</span>\n <span>&lt;ul</span> <span>class</span>=<span>\"nav-links\"</span> <span>id</span>=<span>\"nav-links\"</span><span>&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"{% url 'home' %}\"</span><span>&gt;</span>Home<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"{% url 'about' %}\"</span><span>&gt;</span>About<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"{% url 'contact' %}\"</span><span>&gt;</span>Contact<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;/ul&gt;</span>\n <span>&lt;/nav&gt;</span>\n <span>&lt;/header&gt;</span>\n\n <span>&lt;!-- 8. Flash messages (Django contrib.messages) --&gt;</span>\n <span>{% if messages %}</span>\n <span>&lt;div</span> <span>class</span>=<span>\"messages\"</span><span>&gt;</span>\n <span>{% for message in messages %}</span>\n <span>&lt;p</span> <span>class</span>=<span>\"message message--{{ message.tags }}\"</span><span>&gt;</span>{{ message }}<span>&lt;/p&gt;</span>\n <span>{% endfor %}</span>\n <span>&lt;/div&gt;</span>\n <span>{% endif %}</span>\n\n <span>&lt;!-- 9. Main content block \u2014 every page fills this in --&gt;</span>\n <span>&lt;main</span> <span>class</span>=<span>\"main-content\"</span><span>&gt;</span>\n <span>{% block content %}{% endblock %}</span>\n <span>&lt;/main&gt;</span>\n\n <span>&lt;!-- 10. Shared footer --&gt;</span>\n <span>&lt;footer</span> <span>class</span>=<span>\"site-footer\"</span><span>&gt;</span>\n <span>&lt;p&gt;</span>&amp;copy; {{ <span>now</span>|date:<span>\"Y\"</span> }} MyBrand. All rights reserved.<span>&lt;/p&gt;</span>\n <span>&lt;/footer&gt;</span>\n\n <span>&lt;!-- 11. Scripts loaded at end of body for performance --&gt;</span>\n <span>&lt;script</span> <span>src</span>=<span>\"{% static 'js/nav.js' %}\"</span> <span>defer</span><span>&gt;&lt;/script&gt;</span>\n <span>{% block extra_js %}{% endblock %}</span>\n\n<span>&lt;/body&gt;</span>\n<span>&lt;/html&gt;</span></pre>\n</div>\n<!-- ANATOMY TABLE -->\n<div>\n<div>\n<span>Line / construct</span>\n<span>What it does &amp; why it matters</span>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% load static %}</div>\n<div class=\"anatomy-explain\"><strong>Required first line</strong>Registers the <code>static</code> template tag. Without this, Django raises <code>TemplateSyntaxError</code> on any <code>{% static %}</code> call.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% block title %}My Site{% endblock %}</div>\n<div class=\"anatomy-explain\"><strong>Overrideable title</strong>Child templates call <code>{% block title %}Home{% endblock %}</code>. The default \"My Site\" is the fallback if a page forgets to override it.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% static 'css/main.css' %}</div>\n<div class=\"anatomy-explain\"><strong>Static URL resolution</strong>In dev returns <code>/static/css/main.css</code>. After <code>collectstatic</code> in production, WhiteNoise can hash and fingerprint the filename automatically.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% block extra_head %}{% endblock %}</div>\n<div class=\"anatomy-explain\"><strong>Head injection point</strong>A page that needs its own CSS or meta tags overrides this block. The block is empty by default \u2014 no output.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% url 'home' %}</div>\n<div class=\"anatomy-explain\"><strong>Reverse URL lookup</strong>Generates the correct URL by name rather than hardcoding <code>/</code>. If you ever change the path in <code>urls.py</code>, links update automatically everywhere.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">aria-expanded=\"false\"<br/>aria-controls=\"nav-links\"</div>\n<div class=\"anatomy-explain\"><strong>Accessibility</strong>Screen readers announce the button state. <code>nav.js</code> toggles <code>aria-expanded</code> to \"true\" when the menu opens \u2014 keeping it accurate at runtime.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% if messages %}...{% endif %}</div>\n<div class=\"anatomy-explain\"><strong>Flash messages</strong>Django's messages framework lets any view call <code>messages.success(request, \"Sent!\")</code>. The block renders them automatically and is invisible if there are none.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{% block content %}{% endblock %}</div>\n<div class=\"anatomy-explain\"><strong>Main injection point</strong>Every child template wraps its page body in this block. Nothing else needs to change in base.html to add a new page.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">{{ now|date:\"Y\" }}</div>\n<div class=\"anatomy-explain\"><strong>Dynamic copyright year</strong>Pass <code>now=datetime.now()</code> from a context processor so the year never goes stale in the footer.</div>\n</div>\n<div class=\"anatomy-row\">\n<div class=\"anatomy-code\">&lt;script src=\"...\" defer&gt;</div>\n<div class=\"anatomy-explain\"><strong>Deferred JS</strong><code>defer</code> tells the browser to parse the script after the HTML is ready \u2014 equivalent to placing the tag at the bottom of <code>&lt;body&gt;</code> but without blocking parsing.</div>\n</div>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> Forgetting <code>{% load static %}</code> as the very first line. It must appear before any <code>{% static %}</code> or <code>{% url %}</code> call, and before <code>{% extends %}</code> in child templates too.</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge\">09</div>\n<h2>Navbar HTML \u2014 explained in detail</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The navbar structure directly determines whether it is accessible, responsive, and easy to style. Getting the semantics right now prevents refactoring later.</div>\n<div class=\"step-body\">\n<p>The full navbar markup was embedded in <code>base.html</code> above. Here is an annotated breakdown of every class and attribute decision.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">navbar excerpt \u2014 classes explained</span>\n</div>\n<pre><span>&lt;!-- site-header: full-width strip at top, holds the navbar --&gt;</span>\n<span>&lt;header</span> <span>class</span>=<span>\"site-header\"</span><span>&gt;</span>\n\n <span>&lt;!-- navbar: flex container; role=\"navigation\" implied by &lt;nav&gt; --&gt;</span>\n <span>&lt;nav</span> <span>class</span>=<span>\"navbar\"</span> <span>aria-label</span>=<span>\"Main navigation\"</span><span>&gt;</span>\n\n <span>&lt;!-- nav-brand: logo/brand name; always visible --&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'home' %}\"</span> <span>class</span>=<span>\"nav-brand\"</span><span>&gt;</span>MyBrand<span>&lt;/a&gt;</span>\n\n <span>&lt;!-- nav-toggle: visible on mobile only; hidden on desktop via CSS --&gt;</span>\n <span>&lt;button</span> <span>class</span>=<span>\"nav-toggle\"</span>\n <span>aria-expanded</span>=<span>\"false\"</span>\n <span>aria-controls</span>=<span>\"nav-links\"</span>\n <span>aria-label</span>=<span>\"Toggle menu\"</span><span>&gt;</span>\n <span>&lt;!-- Three &lt;span&gt; elements become the three hamburger lines via CSS --&gt;</span>\n <span>&lt;span&gt;&lt;/span&gt;</span>\n <span>&lt;span&gt;&lt;/span&gt;</span>\n <span>&lt;span&gt;&lt;/span&gt;</span>\n <span>&lt;/button&gt;</span>\n\n <span>&lt;!-- nav-links: the &lt;ul&gt;; on mobile hidden until .open is toggled --&gt;</span>\n <span>&lt;ul</span> <span>class</span>=<span>\"nav-links\"</span> <span>id</span>=<span>\"nav-links\"</span><span>&gt;</span>\n <span>&lt;!-- Each &lt;li&gt; is a nav item; &lt;a&gt; gets .active from nav.js --&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"{% url 'home' %}\"</span><span>&gt;</span>Home<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"{% url 'about' %}\"</span><span>&gt;</span>About<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"{% url 'contact' %}\"</span><span>&gt;</span>Contact<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;/ul&gt;</span>\n\n <span>&lt;/nav&gt;</span>\n<span>&lt;/header&gt;</span></pre>\n</div>\n<div>\n<strong>Why <code>&lt;ul&gt;</code> for the links?</strong> Screen readers announce the number of items in a list (<em>\"navigation, list, 3 items\"</em>). Using bare <code>&lt;a&gt;</code> tags in a row loses that context. The <code>&lt;ul&gt; &gt; &lt;li&gt; &gt; &lt;a&gt;</code> pattern is the semantic standard for navigation menus.\n </div>\n<div class=\"tone-tip\"><strong>Tip:</strong> The <code>aria-label=\"Main navigation\"</code> on <code>&lt;nav&gt;</code> is crucial if you have more than one <code>&lt;nav&gt;</code> on the page (e.g. a sidebar or footer nav). Without it, a screen reader user hears two anonymous \"navigation\" landmarks and can't distinguish them.</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge\">10</div>\n<h2>main.css \u2014 full stylesheet with navbar</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>All site-wide styles live in one file for easy maintenance. The navbar styling handles both desktop (horizontal flex row) and mobile (collapsible drawer) from the same rules using a media query.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/main.css</span>\n</div>\n<pre><span>/* \u2500\u2500\u2500 RESET &amp; VARIABLES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n*, *::before, *::after {\n box-sizing: border-box;\n margin: 0;\n padding: 0;\n}\n\n:root {\n --clr-bg: #ffffff;\n --clr-surface: #f8f9fa;\n --clr-border: #dee2e6;\n --clr-text: #212529;\n --clr-muted: #6c757d;\n --clr-accent: #0d6efd; <span>/* primary brand colour */</span>\n --clr-accent-h:#0b5ed7; <span>/* hover state */</span>\n --nav-h: 64px; <span>/* navbar height \u2014 used by main padding-top */</span>\n --radius: 6px;\n --shadow: 0 1px 3px rgba(0,0,0,.08), 0 4px 12px rgba(0,0,0,.06);\n --font-sans: system-ui, -apple-system, 'Segoe UI', sans-serif;\n --transition: .2s ease;\n}\n\n<span>/* \u2500\u2500\u2500 BASE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\nhtml { scroll-behavior: smooth; }\nbody {\n font-family: var(--font-sans);\n background: var(--clr-bg);\n color: var(--clr-text);\n line-height: 1.6;\n <span>/* push content below fixed navbar */</span>\n padding-top: var(--nav-h);\n}\na { color: var(--clr-accent); text-decoration: none; }\na:hover { text-decoration: underline; }\nimg { max-width: 100%; display: block; }\n\n<span>/* \u2500\u2500\u2500 NAVBAR \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.site-header {\n position: fixed; <span>/* stick to top while scrolling */</span>\n top: 0; left: 0; right: 0;\n height: var(--nav-h);\n background: var(--clr-bg);\n border-bottom: 1px solid var(--clr-border);\n box-shadow: var(--shadow);\n z-index: 1000; <span>/* above all page content */</span>\n}\n\n.navbar {\n display: flex;\n align-items: center;\n justify-content: space-between;\n height: 100%;\n max-width: 1200px;\n margin: 0 auto;\n padding: 0 24px;\n}\n\n<span>/* Brand / logo link */</span>\n.nav-brand {\n font-size: 1.25rem;\n font-weight: 700;\n color: var(--clr-text);\n letter-spacing: -.01em;\n flex-shrink: 0;\n}\n.nav-brand:hover { text-decoration: none; color: var(--clr-accent); }\n\n<span>/* Link list \u2014 horizontal row on desktop */</span>\n.nav-links {\n display: flex;\n align-items: center;\n gap: 4px;\n list-style: none;\n}\n\n.nav-links a {\n display: block;\n padding: 6px 14px;\n border-radius: var(--radius);\n font-size: .9375rem;\n font-weight: 500;\n color: var(--clr-muted);\n transition: color var(--transition), background var(--transition);\n}\n.nav-links a:hover,\n.nav-links a.active { <span>/* .active added by nav.js */</span>\n color: var(--clr-accent);\n background: rgba(13,110,253,.07);\n text-decoration: none;\n}\n.nav-links a.active {\n font-weight: 600;\n}\n\n<span>/* Hamburger button \u2014 hidden on desktop */</span>\n.nav-toggle {\n display: none; <span>/* shown via media query below */</span>\n flex-direction: column;\n justify-content: center;\n gap: 5px;\n width: 40px; height: 40px;\n background: none;\n border: none;\n cursor: pointer;\n padding: 4px;\n border-radius: var(--radius);\n}\n.nav-toggle:hover { background: var(--clr-surface); }\n.nav-toggle span {\n display: block;\n height: 2px;\n border-radius: 2px;\n background: var(--clr-text);\n transition: transform var(--transition), opacity var(--transition);\n}\n<span>/* Animate hamburger into when menu is open */</span>\n.nav-toggle[aria-expanded=\"true\"] span:nth-child(1) {\n transform: translateY(7px) rotate(45deg);\n}\n.nav-toggle[aria-expanded=\"true\"] span:nth-child(2) {\n opacity: 0;\n}\n.nav-toggle[aria-expanded=\"true\"] span:nth-child(3) {\n transform: translateY(-7px) rotate(-45deg);\n}\n\n<span>/* \u2500\u2500\u2500 MOBILE NAV (\u2264768px) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n@media (max-width: 768px) {\n .nav-toggle { display: flex; } <span>/* show hamburger */</span>\n\n .nav-links {\n display: none; <span>/* hidden by default */</span>\n flex-direction: column;\n align-items: stretch;\n gap: 0;\n position: absolute;\n top: var(--nav-h); <span>/* drop down right below header */</span>\n left: 0; right: 0;\n background: var(--clr-bg);\n border-bottom: 1px solid var(--clr-border);\n box-shadow: var(--shadow);\n padding: 8px 16px 16px;\n }\n .nav-links.open { display: flex; } <span>/* toggled by nav.js */</span>\n .nav-links a { padding: 10px 12px; }\n}\n\n<span>/* \u2500\u2500\u2500 FLASH MESSAGES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.messages { max-width: 1200px; margin: 16px auto; padding: 0 24px; }\n.message {\n padding: 12px 16px;\n border-radius: var(--radius);\n margin-bottom: 8px;\n font-size: .9375rem;\n}\n.message--success { background: #d1fae5; color: #065f46; }\n.message--error { background: #fee2e2; color: #991b1b; }\n.message--info { background: #dbeafe; color: #1e40af; }\n\n<span>/* \u2500\u2500\u2500 MAIN CONTENT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.main-content {\n max-width: 1200px;\n margin: 0 auto;\n padding: 48px 24px 80px;\n}\n\n<span>/* \u2500\u2500\u2500 HERO (home page) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.hero {\n text-align: center;\n padding: 80px 24px;\n}\n.hero h1 {\n font-size: clamp(2rem, 5vw, 3.5rem);\n font-weight: 800;\n line-height: 1.1;\n letter-spacing: -.02em;\n margin-bottom: 20px;\n}\n.hero p {\n font-size: 1.125rem;\n color: var(--clr-muted);\n max-width: 560px;\n margin: 0 auto 32px;\n}\n.btn {\n display: inline-block;\n padding: 12px 28px;\n background: var(--clr-accent);\n color: #fff;\n border-radius: var(--radius);\n font-weight: 600;\n font-size: .9375rem;\n transition: background var(--transition), transform var(--transition);\n}\n.btn:hover {\n background: var(--clr-accent-h);\n text-decoration: none;\n transform: translateY(-1px);\n}\n\n<span>/* \u2500\u2500\u2500 CARD GRID (home page features) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.card-grid {\n display: grid;\n grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));\n gap: 24px;\n margin-top: 48px;\n}\n.card {\n background: var(--clr-surface);\n border: 1px solid var(--clr-border);\n border-radius: var(--radius);\n padding: 28px 24px;\n transition: box-shadow var(--transition), transform var(--transition);\n}\n.card:hover {\n box-shadow: var(--shadow);\n transform: translateY(-2px);\n}\n.card-icon { font-size: 2rem; margin-bottom: 12px; }\n.card h3 { font-size: 1.1rem; margin-bottom: 8px; }\n.card p { font-size: .9375rem; color: var(--clr-muted); }\n\n<span>/* \u2500\u2500\u2500 ABOUT PAGE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.about-grid {\n display: grid;\n grid-template-columns: 1fr 1fr;\n gap: 48px;\n align-items: start;\n}\n.about-grid h2 { font-size: 1.75rem; margin-bottom: 16px; }\n.about-grid p { color: var(--clr-muted); margin-bottom: 12px; }\n@media (max-width: 640px) {\n .about-grid { grid-template-columns: 1fr; }\n}\n\n<span>/* \u2500\u2500\u2500 CONTACT PAGE \u2014 FORM \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.contact-form {\n max-width: 540px;\n}\n.form-group {\n display: flex;\n flex-direction: column;\n gap: 6px;\n margin-bottom: 20px;\n}\n.form-group label {\n font-size: .875rem;\n font-weight: 600;\n color: var(--clr-text);\n}\n.form-group input,\n.form-group textarea {\n padding: 10px 14px;\n border: 1px solid var(--clr-border);\n border-radius: var(--radius);\n font-size: 1rem;\n font-family: inherit;\n color: var(--clr-text);\n background: var(--clr-bg);\n transition: border-color var(--transition), box-shadow var(--transition);\n}\n.form-group input:focus,\n.form-group textarea:focus {\n outline: none;\n border-color: var(--clr-accent);\n box-shadow: 0 0 0 3px rgba(13,110,253,.15);\n}\n.form-group textarea { resize: vertical; min-height: 120px; }\n\n<span>/* \u2500\u2500\u2500 FOOTER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.site-footer {\n background: var(--clr-surface);\n border-top: 1px solid var(--clr-border);\n padding: 32px 24px;\n text-align: center;\n font-size: .875rem;\n color: var(--clr-muted);\n}</pre>\n</div>\n<div>\n<strong>Key decisions in the CSS:</strong><br/>\n<code>position: fixed</code> on <code>.site-header</code> keeps the navbar on screen while scrolling. The matching <code>padding-top: var(--nav-h)</code> on <code>body</code> prevents the fixed bar from covering page content.<br/><br/>\n<code>z-index: 1000</code> ensures the navbar floats above all content including dropdowns, modals, and hero images.<br/><br/>\n The mobile drawer uses <code>position: absolute; top: var(--nav-h)</code> so it drops exactly below the header without needing to know the header's pixel height at runtime.\n </div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge\">11</div>\n<h2>nav.js \u2014 active link &amp; mobile toggle</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The active nav link tells users which page they're on \u2014 critical for orientation. The mobile hamburger toggle turns the horizontal link list into a vertical drawer on small screens.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">JavaScript</span>\n<span class=\"code-file\">static/js/nav.js</span>\n</div>\n<pre><span>/* nav.js \u2014 active link highlighting + mobile menu toggle\n Loaded with `defer` so DOM is ready when this runs */</span>\n\n<span>const</span> toggle = document.querySelector(<span>'.nav-toggle'</span>);\n<span>const</span> navLinks = document.querySelector(<span>'.nav-links'</span>);\n<span>const</span> links = document.querySelectorAll(<span>'.nav-links a'</span>);\n\n<span>/* \u2500\u2500 1. Active link \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n<span>/* Compare each link's pathname to the current page pathname. */</span>\n<span>const</span> currentPath = window.location.pathname;\n\nlinks.forEach(<span>link</span> =&gt; {\n <span>/* new URL() normalises the href (handles relative + absolute) */</span>\n <span>const</span> linkPath = <span>new</span> URL(link.href, window.location.origin).pathname;\n\n <span>/* Exact match: mark as active */</span>\n <span>if</span> (linkPath === currentPath) {\n link.classList.add(<span>'active'</span>);\n link.setAttribute(<span>'aria-current'</span>, <span>'page'</span>); <span>// screen-reader hint</span>\n }\n});\n\n<span>/* \u2500\u2500 2. Mobile hamburger toggle \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n<span>if</span> (toggle &amp;&amp; navLinks) {\n toggle.addEventListener(<span>'click'</span>, () =&gt; {\n <span>const</span> isOpen = navLinks.classList.toggle(<span>'open'</span>);\n\n <span>/* Keep aria-expanded in sync so assistive tech knows state */</span>\n toggle.setAttribute(<span>'aria-expanded'</span>, isOpen ? <span>'true'</span> : <span>'false'</span>);\n });\n\n <span>/* 3. Close menu when a link is clicked (navigating away) */</span>\n links.forEach(<span>link</span> =&gt; {\n link.addEventListener(<span>'click'</span>, () =&gt; {\n navLinks.classList.remove(<span>'open'</span>);\n toggle.setAttribute(<span>'aria-expanded'</span>, <span>'false'</span>);\n });\n });\n\n <span>/* 4. Close menu on Escape key \u2014 keyboard accessibility */</span>\n document.addEventListener(<span>'keydown'</span>, e =&gt; {\n <span>if</span> (e.key === <span>'Escape'</span> &amp;&amp; navLinks.classList.contains(<span>'open'</span>)) {\n navLinks.classList.remove(<span>'open'</span>);\n toggle.setAttribute(<span>'aria-expanded'</span>, <span>'false'</span>);\n toggle.focus(); <span>// return focus to the button</span>\n }\n });\n\n <span>/* 5. Close menu if user clicks outside of it */</span>\n document.addEventListener(<span>'click'</span>, e =&gt; {\n <span>if</span> (!navLinks.contains(e.target) &amp;&amp; !toggle.contains(e.target)) {\n navLinks.classList.remove(<span>'open'</span>);\n toggle.setAttribute(<span>'aria-expanded'</span>, <span>'false'</span>);\n }\n });\n}</pre>\n</div>\n<div>\n<strong>Why <code>new URL(link.href, origin).pathname</code> instead of just <code>link.getAttribute('href')</code>?</strong><br/>\n Django's <code>{% url 'home' %}</code> always outputs absolute paths like <code>/</code> or <code>/about/</code>. The <code>new URL()</code> constructor normalises both relative and absolute forms identically, making the comparison safe regardless of Django's URL output format.\n </div>\n<div class=\"tone-tip\"><strong>Tip:</strong> The <code>aria-current=\"page\"</code> attribute is the WCAG-recommended way to identify the current page link to assistive technologies \u2014 it's separate from the visual <code>.active</code> class and should always be set together with it.</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge\">12</div>\n<h2>Home page template</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>This is the minimal pattern every child template follows: extend base, override the title block, fill the content block. Nothing else is needed.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/home.html</span>\n</div>\n<pre><span>{# 1. Extend first \u2014 must be line 1 of the template #}</span>\n<span>{% extends \"base.html\" %}</span>\n\n<span>{# 2. Load static in EVERY child template that uses {% static %} #}</span>\n<span>{% load static %}</span>\n\n<span>{# 3. Override the &lt;title&gt; #}</span>\n<span>{% block title %}</span>Home \u2014 MyBrand<span>{% endblock %}</span>\n\n<span>{# 4. Everything inside this block becomes the page body #}</span>\n<span>{% block content %}</span>\n\n<span>&lt;!-- Hero section --&gt;</span>\n<span>&lt;section</span> <span>class</span>=<span>\"hero\"</span><span>&gt;</span>\n <span>&lt;h1&gt;</span>Welcome to <span>&lt;span</span> <span>style</span>=<span>\"color:var(--clr-accent)\"</span><span>&gt;</span>MyBrand<span>&lt;/span&gt;&lt;/h1&gt;</span>\n <span>&lt;p&gt;</span>A clean, fast Django multi-page website built from scratch and ready to deploy.<span>&lt;/p&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'contact' %}\"</span> <span>class</span>=<span>\"btn\"</span><span>&gt;</span>Get in touch<span>&lt;/a&gt;</span>\n<span>&lt;/section&gt;</span>\n\n<span>&lt;!-- Feature cards \u2014\n Context variable `features` comes from the view (see Step 15) --&gt;</span>\n<span>&lt;section&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"card-grid\"</span><span>&gt;</span>\n <span>{% for feature in features %}</span>\n <span>&lt;div</span> <span>class</span>=<span>\"card\"</span><span>&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"card-icon\"</span><span>&gt;</span>{{ feature.icon }}<span>&lt;/div&gt;</span>\n <span>&lt;h3&gt;</span>{{ feature.title }}<span>&lt;/h3&gt;</span>\n <span>&lt;p&gt;</span>{{ feature.body }}<span>&lt;/p&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>{% endfor %}</span>\n <span>&lt;/div&gt;</span>\n<span>&lt;/section&gt;</span>\n\n<span>{% endblock %}</span></pre>\n</div>\n<div>\n<strong><code>{% extends \"base.html\" %}</code> must be the very first tag.</strong> Any content before it \u2014 including whitespace \u2014 causes a <code>TemplateSyntaxError</code>. Comments using <code>{# ... #}</code> may appear before it because Django strips them before parsing.\n </div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge\">13</div>\n<h2>About page template</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Demonstrates that child templates can have completely different layouts inside the same <code>{% block content %}</code> without touching <code>base.html</code> at all.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/about.html</span>\n</div>\n<pre><span>{% extends \"base.html\" %}</span>\n<span>{% load static %}</span>\n\n<span>{% block title %}</span>About \u2014 MyBrand<span>{% endblock %}</span>\n\n<span>{% block content %}</span>\n<span>&lt;div</span> <span>class</span>=<span>\"about-grid\"</span><span>&gt;</span>\n\n <span>&lt;div&gt;</span>\n <span>&lt;h2&gt;</span>About Us<span>&lt;/h2&gt;</span>\n <span>&lt;p&gt;</span>\n We build fast, accessible, and maintainable web applications\n using Django and modern front-end practices.\n <span>&lt;/p&gt;</span>\n <span>&lt;p&gt;</span>\n Founded in {{ founding_year }}, we have worked with clients\n across {{ countries }} countries.\n <span>&lt;/p&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'contact' %}\"</span> <span>class</span>=<span>\"btn\"</span><span>&gt;</span>Work with us<span>&lt;/a&gt;</span>\n <span>&lt;/div&gt;</span>\n\n <span>&lt;!-- Right column: team list from context --&gt;</span>\n <span>&lt;div&gt;</span>\n <span>&lt;h2&gt;</span>The Team<span>&lt;/h2&gt;</span>\n <span>{% for member in team %}</span>\n <span>&lt;div</span> <span>class</span>=<span>\"card\"</span> <span>style</span>=<span>\"margin-bottom:16px\"</span><span>&gt;</span>\n <span>&lt;h3&gt;</span>{{ member.name }}<span>&lt;/h3&gt;</span>\n <span>&lt;p&gt;</span>{{ member.role }}<span>&lt;/p&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>{% empty %}</span>\n <span>&lt;p&gt;</span>Team bios coming soon.<span>&lt;/p&gt;</span>\n <span>{% endfor %}</span>\n <span>&lt;/div&gt;</span>\n\n<span>&lt;/div&gt;</span>\n<span>{% endblock %}</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> The <code>{% empty %}</code> clause inside a <code>{% for %}</code> loop renders when the list is empty \u2014 better than an <code>{% if %}</code> check around the whole loop.</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge\">14</div>\n<h2>Contact page template &amp; form</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Contact is the most common interactive page. This template shows the correct Django form rendering pattern with <code>{% csrf_token %}</code> \u2014 required for every POST form.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/contact.html</span>\n</div>\n<pre><span>{% extends \"base.html\" %}</span>\n<span>{% load static %}</span>\n\n<span>{% block title %}</span>Contact \u2014 MyBrand<span>{% endblock %}</span>\n\n<span>{% block content %}</span>\n<span>&lt;h1&gt;</span>Get in Touch<span>&lt;/h1&gt;</span>\n<span>&lt;p</span> <span>style</span>=<span>\"color:var(--clr-muted);margin-bottom:32px\"</span><span>&gt;</span>\n Fill in the form and we'll get back to you within 24 hours.\n<span>&lt;/p&gt;</span>\n\n<span>&lt;!-- action=\"\" submits back to the same URL (contact view) --&gt;</span>\n<span>&lt;form</span> <span>class</span>=<span>\"contact-form\"</span> <span>method</span>=<span>\"post\"</span> <span>action</span>=<span>\"\"</span> <span>novalidate</span><span>&gt;</span>\n\n <span>&lt;!-- REQUIRED: prevents Cross-Site Request Forgery attacks --&gt;</span>\n <span>{% csrf_token %}</span>\n\n <span>&lt;div</span> <span>class</span>=<span>\"form-group\"</span><span>&gt;</span>\n <span>&lt;label</span> <span>for</span>=<span>\"id_name\"</span><span>&gt;</span>Your Name<span>&lt;/label&gt;</span>\n <span>&lt;!-- Render field using Django form object OR plain HTML --&gt;</span>\n {{ form.name }}\n <span>{% if form.name.errors %}</span>\n <span>&lt;p</span> <span>style</span>=<span>\"color:#dc2626;font-size:.875rem\"</span><span>&gt;</span>{{ form.name.errors|join:\", \" }}<span>&lt;/p&gt;</span>\n <span>{% endif %}</span>\n <span>&lt;/div&gt;</span>\n\n <span>&lt;div</span> <span>class</span>=<span>\"form-group\"</span><span>&gt;</span>\n <span>&lt;label</span> <span>for</span>=<span>\"id_email\"</span><span>&gt;</span>Email Address<span>&lt;/label&gt;</span>\n {{ form.email }}\n <span>{% if form.email.errors %}</span>\n <span>&lt;p</span> <span>style</span>=<span>\"color:#dc2626;font-size:.875rem\"</span><span>&gt;</span>{{ form.email.errors|join:\", \" }}<span>&lt;/p&gt;</span>\n <span>{% endif %}</span>\n <span>&lt;/div&gt;</span>\n\n <span>&lt;div</span> <span>class</span>=<span>\"form-group\"</span><span>&gt;</span>\n <span>&lt;label</span> <span>for</span>=<span>\"id_message\"</span><span>&gt;</span>Message<span>&lt;/label&gt;</span>\n {{ form.message }}\n <span>{% if form.message.errors %}</span>\n <span>&lt;p</span> <span>style</span>=<span>\"color:#dc2626;font-size:.875rem\"</span><span>&gt;</span>{{ form.message.errors|join:\", \" }}<span>&lt;/p&gt;</span>\n <span>{% endif %}</span>\n <span>&lt;/div&gt;</span>\n\n <span>&lt;button</span> <span>type</span>=<span>\"submit\"</span> <span>class</span>=<span>\"btn\"</span><span>&gt;</span>Send Message<span>&lt;/button&gt;</span>\n\n<span>&lt;/form&gt;</span>\n<span>{% endblock %}</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Never omit <code>{% csrf_token %}</code>.</strong> Django returns HTTP 403 Forbidden on every POST without it. It must be the first child of <code>&lt;form&gt;</code> to make auditing easy.</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge\">15</div>\n<h2>Views \u2014 one per page</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Views are the glue between URLs, templates, and data. Each function receives an <code>HttpRequest</code> and returns an <code>HttpResponse</code>. They handle GET (render template) and POST (process form) separately using the same URL.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">pages/views.py</span>\n</div>\n<pre><span>from</span> datetime <span>import</span> datetime\n<span>from</span> django.shortcuts <span>import</span> render, redirect\n<span>from</span> django.contrib <span>import</span> messages\n<span>from</span> .forms <span>import</span> ContactForm\n\n\n<span># \u2500\u2500 Home \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 #</span>\n<span>def</span> <span>home</span>(request):\n <span>\"\"\"Render the home page with a list of feature cards.\"\"\"</span>\n features = [\n {<span>\"icon\"</span>: <span>\"\"</span>, <span>\"title\"</span>: <span>\"Fast\"</span>, <span>\"body\"</span>: <span>\"Built on Django's battle-tested ORM.\"</span>},\n {<span>\"icon\"</span>: <span>\"\"</span>, <span>\"title\"</span>: <span>\"Secure\"</span>, <span>\"body\"</span>: <span>\"CSRF, XSS and clickjacking protection.\"</span>},\n {<span>\"icon\"</span>: <span>\"\"</span>, <span>\"title\"</span>: <span>\"Responsive\"</span>, <span>\"body\"</span>: <span>\"Works on every screen size.\"</span>},\n ]\n context = {\n <span>\"features\"</span>: features,\n <span>\"now\"</span>: datetime.now(), <span># used by base.html footer copyright year</span>\n }\n <span>return</span> render(request, <span>\"home.html\"</span>, context)\n\n\n<span># \u2500\u2500 About \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 #</span>\n<span>def</span> <span>about</span>(request):\n <span>\"\"\"Render the about page with team data.\"\"\"</span>\n team = [\n {<span>\"name\"</span>: <span>\"Alice Johnson\"</span>, <span>\"role\"</span>: <span>\"Lead Developer\"</span>},\n {<span>\"name\"</span>: <span>\"Bob Smith\"</span>, <span>\"role\"</span>: <span>\"Designer\"</span>},\n {<span>\"name\"</span>: <span>\"Carol White\"</span>, <span>\"role\"</span>: <span>\"Project Manager\"</span>},\n ]\n context = {\n <span>\"team\"</span>: team,\n <span>\"founding_year\"</span>: <span>2020</span>,\n <span>\"countries\"</span>: <span>12</span>,\n <span>\"now\"</span>: datetime.now(),\n }\n <span>return</span> render(request, <span>\"about.html\"</span>, context)\n\n\n<span># \u2500\u2500 Contact \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 #</span>\n<span>def</span> <span>contact</span>(request):\n <span>\"\"\"Render and process the contact form.\n\n GET: Display an empty form.\n POST: Validate and redirect with a success flash message.\n \"\"\"</span>\n <span>if</span> request.method == <span>\"POST\"</span>:\n form = ContactForm(request.POST)\n <span>if</span> form.is_valid():\n <span># In a real app: save to DB or send an email here</span>\n name = form.cleaned_data[<span>\"name\"</span>]\n messages.success(request, <span>f</span><span>\"Thanks {name}! We'll be in touch.\"</span>)\n <span>return</span> redirect(<span>\"contact\"</span>) <span># POST / Redirect / GET pattern</span>\n <span>else</span>:\n form = ContactForm()\n\n context = {<span>\"form\"</span>: form, <span>\"now\"</span>: datetime.now()}\n <span>return</span> render(request, <span>\"contact.html\"</span>, context)</pre>\n</div>\n<div class=\"step-body\"><p>Create <code>pages/forms.py</code> for the contact form class:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">pages/forms.py</span>\n</div>\n<pre><span>from</span> django <span>import</span> forms\n\n<span>class</span> <span>ContactForm</span>(forms.Form):\n name = forms.CharField(\n max_length=<span>100</span>,\n widget=forms.TextInput(attrs={\n <span>\"class\"</span>: <span>\"form-control\"</span>,\n <span>\"placeholder\"</span>: <span>\"Jane Smith\"</span>,\n <span>\"id\"</span>: <span>\"id_name\"</span>,\n })\n )\n email = forms.EmailField(\n widget=forms.EmailInput(attrs={\n <span>\"class\"</span>: <span>\"form-control\"</span>,\n <span>\"placeholder\"</span>: <span>\"jane@example.com\"</span>,\n <span>\"id\"</span>: <span>\"id_email\"</span>,\n })\n )\n message = forms.CharField(\n widget=forms.Textarea(attrs={\n <span>\"class\"</span>: <span>\"form-control\"</span>,\n <span>\"rows\"</span>: <span>5</span>,\n <span>\"id\"</span>: <span>\"id_message\"</span>,\n })\n )</pre>\n</div>\n<div>The <code>redirect(\"contact\")</code> after a valid POST implements the <strong>Post / Redirect / Get</strong> pattern \u2014 prevents the browser \"Resubmit form?\" dialog when the user refreshes the page after submitting.</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge\">16</div>\n<h2>URL routing</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's URL dispatcher maps incoming paths to view functions. Named URLs (<code>name=\"home\"</code>) let templates and views reference routes by name instead of hardcoded paths \u2014 future-proofing any URL restructures.</div>\n<div class=\"step-body\"><p>First, create the app-level URL file:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">pages/urls.py \u2190 create this file</span>\n</div>\n<pre><span>from</span> django.urls <span>import</span> path\n<span>from</span> . <span>import</span> views\n\n<span># app_name enables namespacing: {% url 'pages:home' %} instead of {% url 'home' %}</span>\n<span># Omit it for simple single-app projects where bare names are clearer.</span>\nurlpatterns = [\n path(<span>\"\"</span>, views.home, name=<span>\"home\"</span>),\n path(<span>\"about/\"</span>, views.about, name=<span>\"about\"</span>),\n path(<span>\"contact/\"</span>, views.contact, name=<span>\"contact\"</span>),\n]</pre>\n</div>\n<div class=\"step-body\"><p>Then include the app URLs in the root URL configuration:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/urls.py</span>\n</div>\n<pre><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.urls <span>import</span> path, include\n\nurlpatterns = [\n path(<span>\"admin/\"</span>, admin.site.urls),\n path(<span>\"\"</span>, include(<span>\"pages.urls\"</span>)), <span># mount pages app at root (/)</span>\n]</pre>\n</div>\n<div>\n<strong>Why mount at <code>\"\"</code> (root)?</strong> The Home page lives at <code>/</code>, not <code>/pages/</code>. Mounting the pages app at root means <code>path(\"\", views.home)</code> matches exactly <code>/</code>. If you had a blog app, you'd mount it at <code>path(\"blog/\", include(\"blog.urls\"))</code>.\n </div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge\">17</div>\n<h2>Static files \u2014 dev &amp; production</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Static files (CSS, JS, images) are served differently in development vs production. Understanding the pipeline prevents the most common Django gotcha: missing styles in production.</div>\n<div class=\"step-body\"><p>Test that the dev server finds your static files:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py runserver</pre>\n</div>\n<div>\n In development, Django's <code>StaticFilesMiddleware</code> (auto-enabled when <code>DEBUG=True</code>) serves files from <code>static/</code> automatically. You don't need Nginx or WhiteNoise yet.<br/><br/>\n In <strong>production</strong> (<code>DEBUG=False</code>) Django stops serving statics itself. WhiteNoise takes over because it's inserted in MIDDLEWARE. Run once before each deploy:\n </div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py collectstatic --noinput</pre>\n</div>\n<div>This copies everything from <code>static/</code> into <code>staticfiles/</code> (the <code>STATIC_ROOT</code> folder). WhiteNoise serves files from that folder with correct caching headers. Never edit files directly in <code>staticfiles/</code> \u2014 they will be overwritten on the next <code>collectstatic</code> run.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Add <code>STATICFILES_STORAGE = \"whitenoise.storage.CompressedManifestStaticFilesStorage\"</code> to <code>settings.py</code> to enable automatic gzip compression and cache-busting filename hashing in production.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">18</div>\n<h2>Settings split \u2014 dev vs production</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A single <code>settings.py</code> that works in both environments forces insecure compromises (<code>DEBUG=True</code> in prod, or hardcoded passwords in the repo). Environment variables solve this cleanly.</div>\n<div class=\"step-body\"><p>The <code>settings.py</code> from Step 6 already reads from environment variables via <code>python-dotenv</code>. For production, update your <code>.env</code> (on the server, not in the repo):</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env (on the production server)</span>\n</div>\n<pre>SECRET_KEY=long-random-50-char-string-here\nDEBUG=False\nALLOWED_HOSTS=yourdomain.com www.yourdomain.com\nDATABASE_URL=postgres://user:pass@localhost/dbname</pre>\n</div>\n<div class=\"step-body\"><p>Add these security headers to <code>settings.py</code> \u2014 they only activate when <code>DEBUG=False</code>:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py \u2014 add at the bottom</span>\n</div>\n<pre><span># Production security \u2014 ignored when DEBUG=True</span>\n<span>if not</span> DEBUG:\n SECURE_SSL_REDIRECT = <span>True</span>\n SESSION_COOKIE_SECURE = <span>True</span>\n CSRF_COOKIE_SECURE = <span>True</span>\n SECURE_HSTS_SECONDS = <span>31536000</span> <span># 1 year</span>\n SECURE_HSTS_INCLUDE_SUBDOMAINS = <span>True</span>\n SECURE_HSTS_PRELOAD = <span>True</span>\n SECURE_CONTENT_TYPE_NOSNIFF = <span>True</span>\n X_FRAME_OPTIONS = <span>\"DENY\"</span>\n STATICFILES_STORAGE = <span>\"whitenoise.storage.CompressedManifestStaticFilesStorage\"</span></pre>\n</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">19</div>\n<h2>PostgreSQL for production</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>SQLite is fine for development but is not suitable for production \u2014 it has no concurrent write support and resets on many hosting platforms. PostgreSQL is the industry standard Django database.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install psycopg2-binary dj-database-url\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py \u2014 replace DATABASES block</span>\n</div>\n<pre><span>import</span> dj_database_url\n\nDATABASES = {\n <span>\"default\"</span>: dj_database_url.config(\n default=<span>\"sqlite:///db.sqlite3\"</span>, <span># fallback for local dev</span>\n conn_max_age=<span>600</span>, <span># persistent connection pool</span>\n ssl_require=<span>not</span> DEBUG, <span># TLS in prod, not locally</span>\n )\n}</pre>\n</div>\n<div>Set <code>DATABASE_URL=postgres://user:pass@host/dbname</code> in the production <code>.env</code>. The <code>dj_database_url.config()</code> call reads it automatically. No code change needed between environments.</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">20</div>\n<h2>Gunicorn + Nginx on a VPS</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in server (<code>runserver</code>) is single-threaded and not safe for production traffic. Gunicorn handles concurrent requests; Nginx terminates TLS, serves static files from disk, and acts as a reverse proxy.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">on the production server</span>\n</div>\n<pre>gunicorn core.wsgi:application \\\n --workers 3 \\\n --bind 127.0.0.1:8000 \\\n --access-logfile - \\\n --error-logfile -</pre>\n</div>\n<div><strong>Workers formula:</strong> <code>(2 \u00d7 CPU cores) + 1</code>. A 1-core VPS \u2192 3 workers. A 2-core VPS \u2192 5 workers. Each worker can handle one request at a time.</div>\n<div class=\"step-body\"><p>Nginx configuration:</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">/etc/nginx/sites-available/mysite</span>\n</div>\n<pre>server {\n listen 80;\n server_name yourdomain.com www.yourdomain.com;\n\n <span># Serve collected static files directly \u2014 bypasses Python entirely</span>\n location /static/ {\n alias /path/to/mysite/staticfiles/;\n expires 1y;\n add_header Cache-Control \"public, immutable\";\n }\n\n <span># Forward everything else to Gunicorn</span>\n location / {\n proxy_pass http://127.0.0.1:8000;\n proxy_set_header Host $host;\n proxy_set_header X-Real-IP $remote_addr;\n proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n proxy_set_header X-Forwarded-Proto $scheme;\n }\n}</pre>\n</div>\n<div class=\"step-body\"><p>Enable the site and add HTTPS via Certbot (Let's Encrypt):</p></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>sudo ln -s /etc/nginx/sites-available/mysite /etc/nginx/sites-enabled/\nsudo nginx -t <span># test config</span>\nsudo systemctl reload nginx\nsudo apt install certbot python3-certbot-nginx\nsudo certbot --nginx -d yourdomain.com -d www.yourdomain.com</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip \u2014 PaaS alternative:</strong> To skip server management entirely, deploy to <strong>Railway</strong>, <strong>Render</strong>, or <strong>Fly.io</strong>. Add a <code>Procfile</code> with <code>web: gunicorn core.wsgi:application</code> and they handle Nginx, TLS, and process management for you.</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">21</div>\n<h2>Pre-deploy checklist</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in deploy check catches the most common security misconfigurations automatically. Run it every time before pushing to production.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py check --deploy <span># must return zero errors/warnings</span>\npython manage.py migrate <span># apply any pending DB migrations</span>\npython manage.py collectstatic --noinput</pre>\n</div>\n<div class=\"checklist\">\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>DEBUG = False</code> is set via environment variable</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>SECRET_KEY</code> is a long random string, not in version control</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>ALLOWED_HOSTS</code> lists only your production domain(s)</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>HTTPS</code> is enforced \u2014 <code>SECURE_SSL_REDIRECT = True</code></div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>HSTS</code> header is set \u2014 <code>SECURE_HSTS_SECONDS = 31536000</code></div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>SESSION_COOKIE_SECURE</code> and <code>CSRF_COOKIE_SECURE</code> are <code>True</code></div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>DATABASE_URL</code> points to PostgreSQL (not SQLite)</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>collectstatic</code> has been run and <code>staticfiles/</code> is populated</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>.env</code> and <code>venv/</code> are in <code>.gitignore</code> and not pushed</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div><code>python manage.py check --deploy</code> returns zero issues</div></div>\n<div class=\"checklist-item\"><div class=\"check-box\"></div><div>Error logging is configured \u2014 <strong>Sentry</strong> is highly recommended</div></div>\n</div>\n</section>\n<section id=\"cheatsheet\">\n<h2>Django Multi-Page Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference for templates, static files, URLs, and forms.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Template Inheritance</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% extends \"base.html\" %}</code><span>Must be line 1 \u2014 inherits parent skeleton</span></div>\n<div class=\"cheat-item\"><code>{% block name %}{% endblock %}</code><span>Define or override a named region</span></div>\n<div class=\"cheat-item\"><code>{{ block.super }}</code><span>Include parent block content AND add to it</span></div>\n<div class=\"cheat-item\"><code>{% load static %}</code><span>Required in base AND every child using {% static %}</span></div>\n<div class=\"cheat-item\"><code>{% static 'css/main.css' %}</code><span>Resolves to correct URL in dev and prod</span></div>\n<div class=\"cheat-item\"><code>{% url 'view_name' %}</code><span>Reverse URL lookup by name \u2014 never hardcode paths</span></div>\n<div class=\"cheat-item\"><code>{% include \"partial.html\" %}</code><span>Embed a sub-template (e.g. nav, footer) inline</span></div>\n<div class=\"cheat-item\"><code>{# comment #}</code><span>Template comment \u2014 not rendered to HTML</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>URL Patterns</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>path(\"\", view, name=\"home\")</code><span>Match exactly \"/\" \u2014 the root URL</span></div>\n<div class=\"cheat-item\"><code>path(\"about/\", view, name=\"about\")</code><span>Match \"/about/\" with trailing slash</span></div>\n<div class=\"cheat-item\"><code>path(\"post/&lt;int:pk&gt;/\", view)</code><span>Capture integer segment as view arg</span></div>\n<div class=\"cheat-item\"><code>path(\"post/&lt;slug:slug&gt;/\", view)</code><span>Capture URL-safe string segment</span></div>\n<div class=\"cheat-item\"><code>include(\"app.urls\")</code><span>Mount an app's URL file under a prefix</span></div>\n<div class=\"cheat-item\"><code>redirect(\"view_name\")</code><span>HTTP 302 redirect by URL name</span></div>\n<div class=\"cheat-item\"><code>reverse(\"view_name\")</code><span>Get URL string in Python code</span></div>\n<div class=\"cheat-item\"><code>APPEND_SLASH = True</code><span>Auto-redirect \"/about\" to \"/about/\" (default)</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Static Files Pipeline</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>STATICFILES_DIRS</code><span>Where Django looks for statics in dev</span></div>\n<div class=\"cheat-item\"><code>STATIC_ROOT</code><span>Where collectstatic copies files for prod</span></div>\n<div class=\"cheat-item\"><code>STATIC_URL = \"/static/\"</code><span>URL prefix for all static assets</span></div>\n<div class=\"cheat-item\"><code>collectstatic --noinput</code><span>Gather all statics into STATIC_ROOT</span></div>\n<div class=\"cheat-item\"><code>WhiteNoiseMiddleware</code><span>Serve statics from Gunicorn \u2014 no Nginx needed</span></div>\n<div class=\"cheat-item\"><code>CompressedManifestStaticFilesStorage</code><span>Gzip + cache-bust filenames in prod</span></div>\n<div class=\"cheat-item\"><code>MEDIA_URL / MEDIA_ROOT</code><span>Separate settings for user-uploaded files</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Forms &amp; Requests</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% csrf_token %}</code><span>Required inside every POST &lt;form&gt;</span></div>\n<div class=\"cheat-item\"><code>form.is_valid()</code><span>Run validation; True if no errors</span></div>\n<div class=\"cheat-item\"><code>form.cleaned_data[\"field\"]</code><span>Access validated Python value</span></div>\n<div class=\"cheat-item\"><code>form.errors</code><span>Dict of field \u2192 list of error strings</span></div>\n<div class=\"cheat-item\"><code>request.method == \"POST\"</code><span>Check if form was submitted</span></div>\n<div class=\"cheat-item\"><code>Form(request.POST)</code><span>Bind submitted data to the form</span></div>\n<div class=\"cheat-item\"><code>redirect(\"name\")</code><span>PRG: always redirect after valid POST</span></div>\n<div class=\"cheat-item\"><code>messages.success(req, \"text\")</code><span>Flash message shown on next page</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Views Patterns</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>render(request, \"t.html\", {})</code><span>Shortcut: load template, add context, return response</span></div>\n<div class=\"cheat-item\"><code>get_object_or_404(Model, pk=pk)</code><span>Fetch or raise 404 \u2014 always prefer over .get()</span></div>\n<div class=\"cheat-item\"><code>@login_required</code><span>Decorator: redirect to login if not authenticated</span></div>\n<div class=\"cheat-item\"><code>TemplateView.as_view(...)</code><span>Class-based view for static-content pages</span></div>\n<div class=\"cheat-item\"><code>ListView</code><span>CBV that paginates a queryset automatically</span></div>\n<div class=\"cheat-item\"><code>DetailView</code><span>CBV that fetches one object by pk or slug</span></div>\n<div class=\"cheat-item\"><code>context_object_name</code><span>Override the default \"object\" variable name in template</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Production Security</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>DEBUG = False</code><span>Hides tracebacks and disables dev tooling</span></div>\n<div class=\"cheat-item\"><code>SECURE_SSL_REDIRECT</code><span>Force HTTP \u2192 HTTPS on all requests</span></div>\n<div class=\"cheat-item\"><code>SESSION_COOKIE_SECURE</code><span>Session cookie only sent over HTTPS</span></div>\n<div class=\"cheat-item\"><code>CSRF_COOKIE_SECURE</code><span>CSRF cookie only sent over HTTPS</span></div>\n<div class=\"cheat-item\"><code>SECURE_HSTS_SECONDS</code><span>Tell browsers to always use HTTPS for N seconds</span></div>\n<div class=\"cheat-item\"><code>X_FRAME_OPTIONS = \"DENY\"</code><span>Block clickjacking via iframes</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Django's built-in security audit \u2014 must pass</span></div>\n</div>\n</div>\n</div>\n</section>";

